   637→    absl::optional<StreamInfo::CoreResponseFlag> response_flag, absl::string_view details) {
   638→  if (connection_idle_timer_) {
   639→    connection_idle_timer_->disableTimer();
   640→    connection_idle_timer_.reset();
   641→  }
   642→
   643→  if (connection_duration_timer_) {
   644→    connection_duration_timer_->disableTimer();
   645→    connection_duration_timer_.reset();
   646→  }
   647→
   648→  if (drain_timer_) {
   649→    drain_timer_->disableTimer();
   650→    drain_timer_.reset();
   651→  }
   652→
   653→  if (!streams_.empty()) {
   654→    const Network::ConnectionEvent event = close_type.has_value()
   655→                                               ? Network::ConnectionEvent::LocalClose
   656→                                               : Network::ConnectionEvent::RemoteClose;
   657→    if (event == Network::ConnectionEvent::LocalClose) {
   658→      stats_.named_.downstream_cx_destroy_local_active_rq_.inc();
   659→    }
   660→    if (event == Network::ConnectionEvent::RemoteClose) {
   661→      stats_.named_.downstream_cx_destroy_remote_active_rq_.inc();
   662→    }
   663→
   664→    stats_.named_.downstream_cx_destroy_active_rq_.inc();
   665→    user_agent_.onConnectionDestroy(event, true);
   666→    // Note that resetAllStreams() does not actually write anything to the wire. It just resets
   667→    // all upstream streams and their filter stacks. Thus, there are no issues around recursive
   668→    // entry.
   669→    resetAllStreams(response_flag, details);
   670→  }
   671→
   672→  if (close_type.has_value()) {
   673→    read_callbacks_->connection().close(close_type.value(), details);
   674→  }
