  1131→  const Router::Decorator* decorater = route_decorator_;
  1132→
  1133→  // If a decorator has been defined, apply it to the active span.
  1134→  absl::string_view decorated_operation;
  1135→  if (decorater != nullptr) {
  1136→    decorated_operation = decorater->getOperation();
  1137→
  1138→    decorater->apply(*active_span_);
  1139→    state_.decorated_propagate_ = decorater->propagate();
  1140→  }
