   796→
   797→void ConnectionManagerImpl::sendGoAwayAndClose(bool graceful) {
   798→  ENVOY_CONN_LOG(trace, "connection manager sendGoAwayAndClose was triggerred from filters.",
   799→                 read_callbacks_->connection());
   800→  if (go_away_sent_) {
   801→    return;
   802→  }
   803→
   804→  // Use graceful drain sequence if graceful shutdown is requested.
   805→  // startDrainSequence() works for both HTTP/1 and HTTP/2:
   806→  // - HTTP/1: shutdownNotice() + goAway() provides graceful close
   807→  // - HTTP/2: shutdownNotice() sends GOAWAY with high stream ID, then goAway() sends final GOAWAY
   808→  if (graceful) {
   809→    if (drain_state_ == DrainState::NotDraining) {
   810→      startDrainSequence();
   811→    }
   812→    // Consider the "go away" process started once draining begins.
   813→    // The actual GOAWAY frame will be sent in onDrainTimeout(), but we want to
   814→    // prevent multiple calls to sendGoAwayAndClose() from starting multiple drain sequences.
   815→    go_away_sent_ = true;
   816→  } else {
   817→    // Immediate close - send GOAWAY and close immediately
   818→    codec_->shutdownNotice();
   819→    codec_->goAway();
   820→    go_away_sent_ = true;
   821→    doConnectionClose(Network::ConnectionCloseType::FlushWriteAndDelay, absl::nullopt,
   822→                      "forced_goaway");
   823→  }
   824→}
