   444→  // for doMetadata() to drain the metadata after iteration continues.
   445→  if (!stoppedAll() && saved_request_metadata_ != nullptr && !getSavedRequestMetadata()->empty()) {
   446→    drainSavedRequestMetadata();
   447→  }
   448→  // Restores the original value of iterate_from_current_filter_.
   449→  iterate_from_current_filter_ = saved_state;
