   938→FilterManager::commonEncodePrefix(ActiveStreamEncoderFilter* filter, bool end_stream,
   939→                                  FilterIterationStartState filter_iteration_start_state) {
   940→  // Only do base state setting on the initial call. Subsequent calls for filtering do not touch
   941→  // the base state.
   942→  ENVOY_STREAM_LOG(trace, "commonEncodePrefix end_stream: {}, isHalfCloseEnabled: {}", *this,
   943→                   end_stream, filter_manager_callbacks_.isHalfCloseEnabled());
   944→  if (filter == nullptr) {
   945→    if (end_stream) {
   946→      ASSERT(!state_.observed_encode_end_stream_);
   947→      state_.observed_encode_end_stream_ = true;
   948→
   949→      // When half close semantics are disabled, receiving end stream from the upstream causes
   950→      // decoder filter to stop, as neither filters nor upstream is interested in downstream data.
   951→      // half close is enabled in case tcp proxying is done with http1 encoder. In this case, we
   952→      // should not stop decoder filter chain when end_stream is true, as it will cause any data
   953→      // sent in the upstream direction to be
   954→      // dropped.
   955→      if (!filter_manager_callbacks_.isHalfCloseEnabled()) {
   956→        state_.decoder_filter_chain_aborted_ = true;
   957→      }
   958→    }
   959→    return encoder_filters_.begin();
   960→  }
