   962→  if (filter_iteration_start_state == FilterIterationStartState::CanStartFromCurrent &&
   963→      (*(filter->entry()))->iterate_from_current_filter_) {
   964→    // The filter iteration has been stopped for all frame types, and now the iteration continues.
   965→    // The current filter's encoding callback has not be called. Call it now.
   966→    return filter->entry();
   967→  }
   968→  return std::next(filter->entry());
