    56→bool HeaderMapImpl::HeaderList::maybeMakeMap() {
    57→  if (lazy_map_.empty()) {
    58→    if (headers_.size() < kMinHeadersForLazyMap) {
    59→      return false;
    60→    }
    61→    // Add all entries from the list into the map.
    62→    for (auto node = headers_.begin(); node != headers_.end(); ++node) {
    63→      HeaderNodeVector& v = lazy_map_[node->key().getStringView()];
    64→      v.push_back(node);
    65→    }
    66→  }
    67→  return true;
    68→}
